-- Story Studio: レイヤー構造テンプレート・素材・タグ・お気に入り・下書き
-- タグはテンプレート・素材それぞれと多対多。将来 feed/carousel/reel_cover にも
-- 対応できるよう templates.type を持たせるが、今回は 'story' のみ使用する。

create extension if not exists pg_trgm;
create extension if not exists pgcrypto;

create table if not exists categories (
  id uuid primary key default gen_random_uuid(),
  name text not null unique
);

create table if not exists tags (
  id uuid primary key default gen_random_uuid(),
  name text not null unique
);

create table if not exists templates (
  id uuid primary key default gen_random_uuid(),
  type text not null default 'story' check (type in ('story', 'feed', 'carousel', 'reel_cover')),
  name text not null,
  layer_defaults jsonb not null,
  plan text not null default 'free' check (plan in ('free', 'pro', 'business')),
  score numeric not null default 0,
  thumbnail_url text,
  created_at timestamptz not null default now()
);

create table if not exists assets (
  id uuid primary key default gen_random_uuid(),
  category_id uuid not null references categories(id) on delete restrict,
  name text not null,
  file_url text not null,
  plan text not null default 'free' check (plan in ('free', 'pro', 'business')),
  width int,
  height int,
  created_at timestamptz not null default now()
);

create table if not exists template_tags (
  template_id uuid not null references templates(id) on delete cascade,
  tag_id uuid not null references tags(id) on delete cascade,
  primary key (template_id, tag_id)
);

create table if not exists asset_tags (
  asset_id uuid not null references assets(id) on delete cascade,
  tag_id uuid not null references tags(id) on delete cascade,
  primary key (asset_id, tag_id)
);

create table if not exists favorites (
  user_id uuid not null references auth.users(id) on delete cascade,
  target_type text not null check (target_type in ('template', 'asset')),
  target_id uuid not null,
  created_at timestamptz not null default now(),
  primary key (user_id, target_type, target_id)
);

create table if not exists recent_templates (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  template_id uuid not null references templates(id) on delete cascade,
  used_at timestamptz not null default now()
);

-- 完成物。画像ではなくJSONとして保存し、何度でも再編集できるようにする
create table if not exists story_drafts (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  ig_user_id text,
  template_id uuid references templates(id) on delete set null,
  layers_json jsonb not null,
  scheduled_post_id uuid references scheduled_posts(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

-- インデックス（素材3000件・テンプレート1000件規模でも高速に検索できるように）
create index if not exists idx_asset_tags_tag on asset_tags(tag_id);
create index if not exists idx_template_tags_tag on template_tags(tag_id);
create index if not exists idx_assets_category_plan on assets(category_id, plan);
create index if not exists idx_templates_type_plan on templates(type, plan);
create index if not exists idx_assets_name_trgm on assets using gin (name gin_trgm_ops);
create index if not exists idx_templates_name_trgm on templates using gin (name gin_trgm_ops);
create index if not exists idx_recent_templates_user on recent_templates(user_id, used_at desc);
create index if not exists idx_story_drafts_user on story_drafts(user_id, updated_at desc);

-- RLS
alter table templates enable row level security;
alter table assets enable row level security;
alter table categories enable row level security;
alter table tags enable row level security;
alter table template_tags enable row level security;
alter table asset_tags enable row level security;
alter table favorites enable row level security;
alter table recent_templates enable row level security;
alter table story_drafts enable row level security;

-- テンプレート・素材・タグ・カテゴリはログインユーザーなら誰でも閲覧可（マスタデータ）
drop policy if exists "templates_select" on templates;
create policy "templates_select" on templates for select using (auth.role() = 'authenticated');
drop policy if exists "assets_select" on assets;
create policy "assets_select" on assets for select using (auth.role() = 'authenticated');
drop policy if exists "categories_select" on categories;
create policy "categories_select" on categories for select using (auth.role() = 'authenticated');
drop policy if exists "tags_select" on tags;
create policy "tags_select" on tags for select using (auth.role() = 'authenticated');
drop policy if exists "template_tags_select" on template_tags;
create policy "template_tags_select" on template_tags for select using (auth.role() = 'authenticated');
drop policy if exists "asset_tags_select" on asset_tags;
create policy "asset_tags_select" on asset_tags for select using (auth.role() = 'authenticated');

-- お気に入り・最近使った・下書きは本人のみ
drop policy if exists "favorites_own" on favorites;
create policy "favorites_own" on favorites for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
drop policy if exists "recent_templates_own" on recent_templates;
create policy "recent_templates_own" on recent_templates for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
drop policy if exists "story_drafts_own" on story_drafts;
create policy "story_drafts_own" on story_drafts for all using (auth.uid() = user_id) with check (auth.uid() = user_id);

