-- ===== MVP動作確認用のダミー素材・テンプレート =====
-- 実際の素材は後から差し替える想定。ここではdata URLとして直接埋め込み、
-- Supabase Storageへのアップロードなしでも動作確認できるようにしている。
do $$
declare
  cat_bg uuid; cat_frame uuid; cat_flower uuid;
  asset_bg_beige uuid; asset_bg_pink uuid; asset_frame uuid; asset_flower uuid;
  tag_beauty uuid; tag_food uuid; tag_luxury uuid; tag_simple uuid; tag_natural uuid; tag_beige uuid;
  tpl1 uuid; tpl2 uuid;
begin
  select id into cat_bg from categories where name = '背景';
  select id into cat_frame from categories where name = 'フレーム';
  select id into cat_flower from categories where name = '花';

  insert into assets (category_id, name, file_url, plan, width, height)
    values (cat_bg, 'ベージュ背景', 'data:image/png;base64,', 'free', 1080, 1920)
    returning id into asset_bg_beige;
  insert into assets (category_id, name, file_url, plan, width, height)
    values (cat_bg, 'ピンク背景', 'data:image/png;base64,', 'free', 1080, 1920)
    returning id into asset_bg_pink;
  insert into assets (category_id, name, file_url, plan, width, height)
    values (cat_frame, '花のフレーム', 'data:image/png;base64,', 'pro', 1080, 1920)
    returning id into asset_frame;
  insert into assets (category_id, name, file_url, plan, width, height)
    values (cat_flower, '花クラスター', 'data:image/png;base64,', 'free', 400, 214)
    returning id into asset_flower;

  select id into tag_beauty from tags where name = '美容室';
  select id into tag_food from tags where name = '飲食店';
  select id into tag_luxury from tags where name = '高級感';
  select id into tag_simple from tags where name = 'シンプル';
  select id into tag_natural from tags where name = 'ナチュラル';
  select id into tag_beige from tags where name = 'ベージュ';

  insert into asset_tags (asset_id, tag_id) values
    (asset_bg_beige, tag_beige), (asset_bg_beige, tag_natural),
    (asset_bg_pink, tag_beauty),
    (asset_frame, tag_luxury), (asset_frame, tag_natural),
    (asset_flower, tag_natural), (asset_flower, tag_beige);

  insert into templates (type, name, layer_defaults, plan, score, thumbnail_url) values
    ('story', 'ナチュラル花フレーム', jsonb_build_object(
      'background', jsonb_build_object('assetId', asset_bg_beige),
      'frame', jsonb_build_object('assetId', asset_frame),
      'flower', jsonb_build_object('assetId', asset_flower),
      'photoSlots', 1,
      'font', 'luxury',
      'titleColor', '#FFFFFF'
    ), 'free', 90, 'data:image/png;base64,')
    returning id into tpl1;
  insert into templates (type, name, layer_defaults, plan, score, thumbnail_url) values
    ('story', 'シンプルベージュ', jsonb_build_object(
      'background', jsonb_build_object('assetId', asset_bg_beige),
      'photoSlots', 1,
      'font', 'default',
      'titleColor', '#333333'
    ), 'free', 80, null)
    returning id into tpl2;

  insert into template_tags (template_id, tag_id) values
    (tpl1, tag_beauty), (tpl1, tag_luxury), (tpl1, tag_natural),
    (tpl2, tag_simple), (tpl2, tag_beige);
end $$;
